external_knowledge:
- "maestros" refers to the composers;
- "size of their musical legacies" means the number of pieces each composer has written;
- "symphony of compositions" metaphorically refers to the collection of musical pieces.

sql:
SELECT title, year_composed
FROM music_pieces
WHERE composer_id = (SELECT composer_id FROM composers WHERE composer_name = 'Ludwig van Beethoven');

SELECT performer_name 
FROM performers 
WHERE nationality = 'British' AND awards IS NOT NULL;

SELECT COUNT(*) 
FROM music_types 
WHERE type_name LIKE 'O%';

SELECT title, duration
FROM music_pieces
WHERE duration = (SELECT MAX(duration) FROM music_pieces);

SELECT location, COUNT(*) 
FROM performances 
GROUP BY location;

SELECT music_pieces.title, music_pieces.year_composed, composers.composer_name
FROM music_pieces
JOIN composers ON music_pieces.composer_id = composers.composer_id
WHERE composers.nationality = (
    SELECT nationality FROM composers WHERE composer_id = 1
);

SELECT role
FROM performance_performers
WHERE performer_id = 0;
